local ILK_MODE = trueintroStartTick = 0local fadeInDuration = 2000local holdDuration = 8000local fadeOutDuration = 2000local totalDuration = fadeInDuration + holdDuration + fadeOutDurationlocal fontBig = dxCreateFont(":mek_ui/public/fonts/BebasNeueBold.otf", 100) or "default"local fontSmall = dxCreateFont(":mek_ui/public/fonts/BebasNeueRegular.otf", 30) or "default"local introSound = nillocal introInitialized = falsefunction drawLegacyIntro()	local nowTick = getTickCount()	local elapsed = nowTick - introStartTick		if elapsed < 0 then return end		local text = "MEKAN GAME"	local textWidth = dxGetTextWidth(text, 1, fontBig)	local textHeight = dxGetFontHeight(1, fontBig)	local textX = screenSize.x / 2 - textWidth / 2	local textY = screenSize.y / 2 - textHeight / 2		local alpha = 0		if elapsed < 1000 then		local progress = elapsed / 1000		alpha = interpolateBetween(0, 0, 0, 255, 0, 0, progress, "InOutQuad")	elseif elapsed < 3500 then		alpha = 255	elseif elapsed < 4500 then		local fadeOutStart = 3500		local fadeOutProgress = (elapsed - fadeOutStart) / 1000		alpha = interpolateBetween(255, 0, 0, 0, 0, 0, fadeOutProgress, "InOutQuad")	else		alpha = 0		finishIntro()	end		dxDrawText(text, textX, textY, textX + textWidth, textY + textHeight, tocolor(255, 255, 255, alpha), 1, fontBig, "left", "top")endlocal glitchChars = {"#", "$", "%", "&", "{", "}", "[", "]", "!", "?", "<", ">", "@", "*"}function drawModernIntro()    local nowTick = getTickCount()    local elapsed = nowTick - introStartTick    if not introSound and elapsed >= 0 and elapsed < totalDuration then        Music.stop(true) -- Global müzigi sustur        introSound = playSound(":mek_account/public/sounds/dystopian.wav")        setSoundVolume(introSound, 1.0)    end    if elapsed > totalDuration then        finishIntro()        return    end    local bgAlpha = 0    if elapsed < fadeInDuration then        bgAlpha = interpolateBetween(0, 0, 0, 30, 0, 0, elapsed / fadeInDuration, "Linear")    elseif elapsed < (fadeInDuration + holdDuration) then        bgAlpha = 30    else        bgAlpha = interpolateBetween(30, 0, 0, 0, 0, 0, (elapsed - (fadeInDuration + holdDuration)) / fadeOutDuration, "Linear")    end    local rot = (nowTick / 50) % 360    local logoSize = screenSize.y * 1.5    -- dxDrawImage(screenSize.x/2 - logoSize/2, screenSize.y/2 - logoSize/2, logoSize, logoSize, ":mek_ui/public/images/logo.png", rot, 0, 0, tocolor(255, 255, 255, bgAlpha))    local animProgress = elapsed / totalDuration    local scale = interpolateBetween(0.9, 0, 0, 1.1, 0, 0, animProgress, "Linear")    local mainText = "MEKAN GAME"    local subText = "Taklit edersiniz, gecemezsiniz."    local textAlpha = 0    if elapsed < fadeInDuration then        textAlpha = interpolateBetween(0, 0, 0, 255, 0, 0, elapsed / fadeInDuration, "InOutQuad")    elseif elapsed < (fadeInDuration + holdDuration) then        textAlpha = 255    else        textAlpha = interpolateBetween(255, 0, 0, 0, 0, 0, (elapsed - (fadeInDuration + holdDuration)) / fadeOutDuration, "InOutQuad")    end    local drawText = mainText    local offsetX, offsetY = 0, 0    local r, g, b = 255, 255, 255        if textAlpha > 100 and math.random(100) < 5 then        local charIndex = math.random(1, #mainText)        local randomChar = glitchChars[math.random(1, #glitchChars)]        drawText = string.sub(mainText, 1, charIndex - 1) .. randomChar .. string.sub(mainText, charIndex + 1)                offsetX = math.random(-5, 5)        offsetY = math.random(-5, 5)                local glitchColor = math.random(1, 3)        if glitchColor == 1 then r, g, b = 255, 0, 0 end        if glitchColor == 2 then r, g, b = 0, 255, 255 end        if glitchColor == 3 then r, g, b = 255, 0, 255 end                dxDrawText(drawText,             offsetX + 5, offsetY, screenSize.x + offsetX + 5, screenSize.y + offsetY,             tocolor(r, g, b, textAlpha * 0.5),             scale, fontBig,             "center", "center")    end    dxDrawText(drawText,         offsetX, offsetY, screenSize.x + offsetX, screenSize.y + offsetY,         tocolor(r, g, b, textAlpha),         scale, fontBig,         "center", "center")    local scanlineY = (nowTick / 20) % screenSize.y    dxDrawRectangle(0, scanlineY, screenSize.x, 2, tocolor(255, 255, 255, 20))        for i=1, screenSize.y, 4 do        dxDrawRectangle(0, i, screenSize.x, 1, tocolor(0, 0, 0, 30))    end    local subElapsed = elapsed - 1500    local subAlpha = 0    if subElapsed > 0 then        if subElapsed < fadeInDuration then            subAlpha = interpolateBetween(0, 0, 0, 150, 0, 0, subElapsed / fadeInDuration, "InOutQuad")        elseif subElapsed < (fadeInDuration + holdDuration) then            subAlpha = 150        else             subAlpha = interpolateBetween(150, 0, 0, 0, 0, 0, (elapsed - (fadeInDuration + holdDuration)) / fadeOutDuration, "InOutQuad")        end    end    dxDrawText(subText,         0, screenSize.y/2 + 60, screenSize.x, screenSize.y,         tocolor(200, 200, 200, subAlpha),         1, fontSmall,         "center", "top")    dxDrawImage(0, 0, screenSize.x, screenSize.y, ":mek_ui/public/images/vignette.png", 0, 0, 0, tocolor(255, 255, 255, 150))    local barHeight = screenSize.y * 0.1    local barMove = 0    if elapsed < fadeInDuration then         barMove = interpolateBetween(barHeight, 0, 0, 0, 0, 0, elapsed / fadeInDuration, "OutQuad")    elseif elapsed > (totalDuration - fadeOutDuration) then         barMove = interpolateBetween(0, 0, 0, barHeight, 0, 0, (elapsed - (totalDuration - fadeOutDuration)) / fadeOutDuration, "InQuad")    end        dxDrawRectangle(0, 0 - barMove, screenSize.x, barHeight, tocolor(0, 0, 0, 255))    dxDrawRectangle(0, screenSize.y - barHeight + barMove, screenSize.x, barHeight, tocolor(0, 0, 0, 255))endlocal activeIntroMode = nillocal lastStartTick = 0function finishIntro()    if not passedIntro then        startAccountFadeIn()        passedIntro = true                if introSound and isElement(introSound) then            stopSound(introSound)            introSound = nil        end                if ILK_MODE and activeIntroMode == "modern" then            exports.mek_json:save("intro_data", { seen = true }, true)        end                -- Intro bitince (Modern veya Legacy farketmez) ana müzigi baslat        Music.play()    endendfunction drawIntro()    if introStartTick ~= lastStartTick then        lastStartTick = introStartTick                activeIntroMode = "modern"                if ILK_MODE then            local data, status = exports.mek_json:get("intro_data", true)            if status and data and data.seen then                activeIntroMode = "legacy"            end        end    end    if activeIntroMode == "modern" then        drawModernIntro()    else        drawLegacyIntro()    endend